from PIL import Image

try:
    import face_recognition
except Exception as e:
    face_recognition = None

APP_NAME = "office_face_recognition_api"
DEFAULT_MODEL_PATH = os.environ.get("FACE_MODEL_PATH", "./face_model.pkl")
DEFAULT_TRAIN_DIR = os.environ.get("FACE_TRAIN_DIR", "./employees")
DEFAULT_UPSAMPLE = int(os.environ.get("FACE_UPSAMPLE", "1"))
DEFAULT_JITTERS = int(os.environ.get("FACE_JITTERS", "1"))
DEFAULT_NUM_JOBS = int(os.environ.get("FACE_NUM_JOBS", "1"))
DEFAULT_TOLERANCE = float(os.environ.get("FACE_TOLERANCE", "0.6"))
DEFAULT_MIN_FACE_SIZE = int(os.environ.get("FACE_MIN_SIZE", "40"))
DEFAULT_ALLOW_MULTIPLE_FACES = os.environ.get("FACE_ALLOW_MULTIPLE", "0").lower() in ("1", "true", "yes")
DEFAULT_DETECTOR = os.environ.get("FACE_DETECTOR", "hog").lower()  # hog or cnn (cnn requires dlib compiled with cuda for speed)

_LOCK = threading.RLock()


def _now_ms() -> int:
    return int(time.time() * 1000)


def _sha256_bytes(b: bytes) -> str:
    return hashlib.sha256(b).hexdigest()


def _softmax(x: np.ndarray) -> np.ndarray:
    x = x.astype(np.float64)
    x = x - np.max(x)
    ex = np.exp(x)
    s = np.sum(ex)
    if s == 0:
        return np.ones_like(x) / len(x)
    return ex / s


def _read_image_bytes(file_bytes: bytes) -> np.ndarray:
    try:
        img = Image.open(io.BytesIO(file_bytes)).convert("RGB")
    except Exception:
        raise HTTPException(status_code=400, detail="Invalid image")
    return np.array(img)


def _list_image_files(root: str) -> List[str]:
    exts = {".jpg", ".jpeg", ".png", ".bmp", ".tif", ".tiff"}
    out = []
    for dirpath, _, filenames in os.walk(root):
        for fn in filenames:
            _, ext = os.path.splitext(fn.lower())
            if ext in exts:
                out.append(os.path.join(dirpath, fn))
    return sorted(out)


def _employee_id_from_path(train_dir: str, path: str) -> str:
    rel = os.path.relpath(path, train_dir)
    parts = rel.split(os.sep)
    if len(parts) < 2:
        return os.path.splitext(parts[0])[0]
    return parts[0]


def _compute_face_encodings(image_rgb: np.ndarray, upsample: int, jitters: int, detector: str) -> Tuple[List[Tuple[int, int, int, int]], List[np.ndarray]]:
    if face_recognition is None:
        raise HTTPException(status_code=500, detail="face_recognition dependency not available. Install: pip install face_recognition")
    boxes = face_recognition.face_locations(image_rgb, number_of_times_to_upsample=upsample, model=detector)
    encs = face_recognition.face_encodings(image_rgb, known_face_locations=boxes, num_jitters=jitters)
    return boxes, [np.array(e, dtype=np.float32) for e in encs]


def _box_area(box: Tuple[int, int, int, int]) -> int:
    top, right, bottom, left = box
    return max(0, bottom - top) * max(0, right - left)


def _largest_face(boxes: List[Tuple[int, int, int, int]], encs: List[np.ndarray]) -> Tuple[Optional[Tuple[int, int, int, int]], Optional[np.ndarray]]:
    if not boxes or not encs:
        return None, None
    idx = int(np.argmax([_box_area(b) for b in boxes]))
    return boxes[idx], encs[idx]


@dataclass
class FaceModel:
    classes: List[str]
    centroids: np.ndarray  # shape (K, 128)
    class_counts: np.ndarray  # shape (K,)
    train_dir: str
    created_at_ms: int
    model_version: int
    parameters: Dict[str, object]
    training_hash: str

    def to_bytes(self) -> bytes:
        payload = {
            "classes": self.classes,
            "centroids": self.centroids.astype(np.float32),
            "class_counts": self.class_counts.astype(np.int64),
            "train_dir": self.train_dir,
            "created_at_ms": self.created_at_ms,
            "model_version": self.model_version,
            "parameters": self.parameters,
            "training_hash": self.training_hash,
        }
        return pickle.dumps(payload, protocol=pickle.HIGHEST_PROTOCOL)

    @staticmethod
    def from_bytes(b: bytes) -> "FaceModel":
        payload = pickle.loads(b)
        return FaceModel(
            classes=list(payload["classes"]),
            centroids=np.array(payload["centroids"], dtype=np.float32),
            class_counts=np.array(payload["class_counts"], dtype=np.int64),
            train_dir=str(payload.get("train_dir", "")),
            created_at_ms=int(payload.get("created_at_ms", 0)),
            model_version=int(payload.get("model_version", 1)),
            parameters=dict(payload.get("parameters", {})),
            training_hash=str(payload.get("training_hash", "")),
        )


def _compute_training_hash(train_dir: str, params: Dict[str, object]) -> str:
    files = _list_image_files(train_dir)
    h = hashlib.sha256()
    h.update(json.dumps(params, sort_keys=True).encode("utf-8"))
    for p in files:
        try:
            st = os.stat(p)
            h.update(p.encode("utf-8"))
            h.update(str(st.st_size).encode("utf-8"))
            h.update(str(int(st.st_mtime)).encode("utf-8"))
        except Exception:
            continue
    return h.hexdigest()


def train_model(
    train_dir: str = DEFAULT_TRAIN_DIR,
    upsample: int = DEFAULT_UPSAMPLE,
    jitters: int = DEFAULT_JITTERS,
    detector: str = DEFAULT_DETECTOR,
    min_face_size: int = DEFAULT_MIN_FACE_SIZE,
    num_jobs: int = DEFAULT_NUM_JOBS,
) -> FaceModel:
    if face_recognition is None:
        raise HTTPException(status_code=500, detail="face_recognition dependency not available. Install: pip install face_recognition")

    params = {
        "upsample": upsample,
        "jitters": jitters,
        "detector": detector,
        "min_face_size": min_face_size,
        "num_jobs": num_jobs,
    }
    training_hash = _compute_training_hash(train_dir, params)

    img_paths = _list_image_files(train_dir)
    if not img_paths:
        raise HTTPException(status_code=400, detail=f"No training images found under: {train_dir}")

    per_class_encs: Dict[str, List[np.ndarray]] = {}
    skipped = 0

    for path in img_paths:
        emp_id = _employee_id_from_path(train_dir, path)
        try:
            image = face_recognition.load_image_file(path)
        except Exception:
            skipped += 1
            continue

        boxes, encs = _compute_face_encodings(image, upsample=upsample, jitters=jitters, detector=detector)
        if not boxes or not encs:
            skipped += 1
            continue

        box, enc = _largest_face(boxes, encs)
        if box is None or enc is None:
            skipped += 1
            continue

        top, right, bottom, left = box
        if (bottom - top) < min_face_size or (right - left) < min_face_size:
            skipped += 1
            continue

        per_class_encs.setdefault(emp_id, []).append(enc)

    if not per_class_encs:
        raise HTTPException(status_code=400, detail="No usable face encodings found in training set")

    classes = sorted(per_class_encs.keys())
    centroids = []
    counts = []
    for c in classes:
        arr = np.stack(per_class_encs[c], axis=0).astype(np.float32)
        centroid = np.mean(arr, axis=0)
        centroid = centroid / (np.linalg.norm(centroid) + 1e-12)
        centroids.append(centroid)
        counts.append(arr.shape[0])

    model = FaceModel(
        classes=classes,
        centroids=np.stack(centroids, axis=0).astype(np.float32),
        class_counts=np.array(counts, dtype=np.int64),
        train_dir=train_dir,
        created_at_ms=_now_ms(),
        model_version=1,
        parameters={**params, "skipped_images": skipped, "num_classes": len(classes), "num_images": len(img_paths)},
        training_hash=training_hash,
    )
    return model


def save_model(model: FaceModel, path: str = DEFAULT_MODEL_PATH) -> None:
    tmp = path + ".tmp"
    with open(tmp, "wb") as f:
        f.write(model.to_bytes())
    os.replace(tmp, path)


def load_model(path: str = DEFAULT_MODEL_PATH) -> FaceModel:
    with open(path, "rb") as f:
        return FaceModel.from_bytes(f.read())


def _ensure_model_loaded(state: dict) -> FaceModel:
    with _LOCK:
        m = state.get("model")
        if m is not None:
            return m
        if os.path.exists(DEFAULT_MODEL_PATH):
            m = load_model(DEFAULT_MODEL_PATH)
            state["model"] = m
            return m
        m = train_model(train_dir=DEFAULT_TRAIN_DIR)
        save_model(m, DEFAULT_MODEL_PATH)
        state["model"] = m
        return m


def _encode_face_from_upload(
    file_bytes: bytes,
    upsample: int,
    jitters: int,
    detector: str,
    min_face_size: int,
    allow_multiple: bool,
) -> Tuple[List[Dict[str, object]], List[np.ndarray]]:
    img = _read_image_bytes(file_bytes)
    boxes, encs = _compute_face_encodings(img, upsample=upsample, jitters=jitters, detector=detector)
    if not boxes or not encs:
        return [], []

    faces = []
    kept_encs = []
    for box, enc in zip(boxes, encs):
        top, right, bottom, left = box
        if (bottom - top) < min_face_size or (right - left) < min_face_size:
            continue
        enc = enc.astype(np.float32)
        enc = enc / (np.linalg.norm(enc) + 1e-12)
        faces.append({"box": {"top": int(top), "right": int(right), "bottom": int(bottom), "left": int(left)}, "area": int(_box_area(box))})
        kept_encs.append(enc)

    if not faces:
        return [], []

    if allow_multiple:
        return faces, kept_encs

    idx = int(np.argmax([f["area"] for f in faces]))
    return [faces[idx]], [kept_encs[idx]]


def _distribution_for_encoding(model: FaceModel, enc: np.ndarray, temperature: float = 0.08) -> Dict[str, object]:
    C = model.centroids  # (K, 128)
    diffs = C - enc.reshape(1, -1)
    dists = np.sqrt(np.sum(diffs * diffs, axis=1) + 1e-12)  # euclidean
    sims = 1.0 - dists  # higher is better
    logits = sims / max(1e-6, float(temperature))
    probs = _softmax(logits)

    order = np.argsort(-probs)
    dist_list = []
    for i in order:
        dist_list.append(
            {
                "class": model.classes[int(i)],
                "probability": float(probs[int(i)]),
                "distance": float(dists[int(i)]),
                "similarity": float(sims[int(i)]),
                "support_images": int(model.class_counts[int(i)]),
            }
        )

    best_i = int(order[0])
    return {
        "best_class": model.classes[best_i],
        "best_probability": float(probs[best_i]),
        "best_distance": float(dists[best_i]),
        "distribution": dist_list,
    }


class TrainRequest(BaseModel):
    train_dir: str = DEFAULT_TRAIN_DIR
    upsample: int = DEFAULT_UPSAMPLE
    jitters: int = DEFAULT_JITTERS
    detector: str = DEFAULT_DETECTOR
    min_face_size: int = DEFAULT_MIN_FACE_SIZE
    num_jobs: int = DEFAULT_NUM_JOBS
    save_path: str = DEFAULT_MODEL_PATH


class PredictParams(BaseModel):
    temperature: float = 0.08
    upsample: int = DEFAULT_UPSAMPLE
    jitters: int = DEFAULT_JITTERS
    detector: str = DEFAULT_DETECTOR
    min_face_size: int = DEFAULT_MIN_FACE_SIZE
    allow_multiple_faces: bool = DEFAULT_ALLOW_MULTIPLE_FACES
    tolerance: float = DEFAULT_TOLERANCE


app = FastAPI(title=APP_NAME, version="1.0.0")
_state: Dict[str, object] = {}


@app.get("/health")
def health():
    return {"ok": True, "time_ms": _now_ms()}


@app.get("/model")
def model_info():
    m = _ensure_model_loaded(_state)
    return {
        "classes": m.classes,
        "class_counts": m.class_counts.tolist(),
        "num_classes": len(m.classes),
        "created_at_ms": m.created_at_ms,
        "model_version": m.model_version,
        "train_dir": m.train_dir,
        "parameters": m.parameters,
        "training_hash": m.training_hash,
        "model_path": DEFAULT_MODEL_PATH,
    }


@app.post("/train")
def train(req: TrainRequest = Body(...)):
    with _LOCK:
        m = train_model(
            train_dir=req.train_dir,
            upsample=req.upsample,
            jitters=req.jitters,
            detector=req.detector,
            min_face_size=req.min_face_size,
            num_jobs=req.num_jobs,
        )
        save_model(m, req.save_path)
        _state["model"] = m
    return {
        "trained": True,
        "saved_to": req.save_path,
        "num_classes": len(m.classes),
        "classes": m.classes,
        "class_counts": m.class_counts.tolist(),
        "parameters": m.parameters,
        "training_hash": m.training_hash,
        "created_at_ms": m.created_at_ms,
    }


@app.post("/predict")
async def predict(
    image: UploadFile = File(...),
    params: str = Body(default="{}", embed=True),
):
    try:
        p = PredictParams(**json.loads(params or "{}"))
    except Exception:
        raise HTTPException(status_code=400, detail="Invalid params JSON")

    m = _ensure_model_loaded(_state)

    file_bytes = await image.read()
    if not file_bytes:
        raise HTTPException(status_code=400, detail="Empty upload")

    faces, encs = _encode_face_from_upload(
        file_bytes=file_bytes,
        upsample=p.upsample,
        jitters=p.jitters,
        detector=p.detector,
        min_face_size=p.min_face_size,
        allow_multiple=p.allow_multiple_faces,
    )

    if not faces:
        return JSONResponse(
            status_code=200,
            content={
                "image_sha256": _sha256_bytes(file_bytes),
                "num_faces": 0,
                "faces": [],
                "model": {"num_classes": len(m.classes), "training_hash": m.training_hash},
            },
        )

    results = []
    for face_meta, enc in zip(faces, encs):
        dist = _distribution_for_encoding(m, enc, temperature=p.temperature)
        best_distance = dist["best_distance"]
        is_match = bool(best_distance <= p.tolerance)
        results.append(
            {
                "face": face_meta,
                "match": {
                    "is_match": is_match,
                    "tolerance": float(p.tolerance),
                    "best_class": dist["best_class"],
                    "best_probability": dist["best_probability"],
                    "best_distance": best_distance,
                },
                "probability_distribution": dist["distribution"],
            }
        )

    return {
        "image_sha256": _sha256_bytes(file_bytes),
        "num_faces": len(results),
        "faces": results,
        "model": {
            "num_classes": len(m.classes),
            "classes": m.classes,
            "class_counts": m.class_counts.tolist(),
            "training_hash": m.training_hash,
            "created_at_ms": m.created_at_ms,
            "parameters": m.parameters,
        },
        "timing_ms": {"server_time_ms": _now_ms()},
    }


